const express = require('express');
const twilio = require('twilio');
const crypto = require('crypto');
const app = express();

app.use(express.json());

const client = twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
const codes = new Map();
const MAX_ATTEMPTS = 3;
const CODE_EXPIRY = 300000; // 5 minutes

const generateCode = () => {
  return crypto.randomInt(100000, 999999).toString();
};

const isValidPhoneNumber = (phone) => {
  const phoneRegex = /^\+?[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
};

const sendSMS = async (to, code) => {
  try {
    await client.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: to
    });
    return true;
  } catch (error) {
    console.error('SMS sending failed:', error);
    return false;
  }
};

const storeCode = (userId, phone, code) => {
  const key = `${userId}:${phone}`;
  codes.set(key, {
    code,
    attempts: 0,
    createdAt: Date.now()
  });
};

const getCode = (userId, phone) => {
  const key = `${userId}:${phone}`;
  const stored = codes.get(key);
  
  if (!stored) return null;
  
  if (Date.now() - stored.createdAt > CODE_EXPIRY) {
    codes.delete(key);
    return null;
  }
  
  return stored;
};

const verifyCode = (userId, phone, inputCode) => {
  const key = `${userId}:${phone}`;
  const stored = codes.get(key);
  
  if (!stored) return false;
  
  if (Date.now() - stored.createdAt > CODE_EXPIRY) {
    codes.delete(key);
    return false;
  }
  
  if (stored.attempts >= MAX_ATTEMPTS) {
    codes.delete(key);
    return false;
  }
  
  if (stored.code === inputCode) {
    codes.delete(key);
    return true;
  }
  
  stored.attempts += 1;
  codes.set(key, stored);
  return false;
};

app.post('/auth/mfa/send', async (req, res) => {
  try {
    const { userId, phone } = req.body;
    
    if (!userId || !phone) {
      return res.status(400).json({ error: 'User ID and phone number required' });
    }
    
    if (!isValidPhoneNumber(phone)) {
      return res.status(400).json({ error: 'Invalid phone number format' });
    }
    
    const code = generateCode();
    storeCode(userId, phone, code);
    
    const sent = await sendSMS(phone, code);
    
    if (!sent) {
      return res.status(500).json({ error: 'Failed to send SMS' });
    }
    
    res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    console.error('MFA send error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/auth/mfa/verify', (req, res) => {
  try {
    const { userId, phone, code } = req.body;
    
    if (!userId || !phone || !code) {
      return res.status(400).json({ error: 'All fields required' });
    }
    
    if (code.length !== 6 || !/^\d{6}$/.test(code)) {
      return res.status(400).json({ error: 'Invalid code format' });
    }
    
    const isValid = verifyCode(userId, phone, code);
    
    if (isValid) {
      res.json({ success: true, message: 'Verification successful' });
    } else {
      res.status(401).json({ error: 'Invalid or expired code' });
    }
  } catch (error) {
    console.error('MFA verify error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = app;